const CustomError = require('custom-service-error');

function ValidationError(meta) {
  this.name = 'ValidationError';
  this.message = 'Validation Error';
  this.status = 406;
  this.code = 400208001;
  this.meta = meta || {};
  CustomError.call(this);
}

ValidationError.prototype = CustomError.prototype;
module.exports.ValidationError = ValidationError;

function DisplayTokenUpdate() {
  this.name = 'DisplayTokenUpdate';
  this.message = 'Error occured during saving display token';
  this.status = 500;
  this.code = 400203001;
  CustomError.call(this);
}

DisplayTokenUpdate.prototype = CustomError.prototype;
module.exports.DisplayTokenUpdate = DisplayTokenUpdate;

function DisplayTokenNotFound() {
  this.name = 'DisplayTokenNotFound';
  this.message = 'Display token not found';
  this.status = 404;
  this.code = 400202001;
  CustomError.call(this);
}

DisplayTokenNotFound.prototype = CustomError.prototype;
module.exports.DisplayTokenNotFound = DisplayTokenNotFound;
